import pandas as pd

df = pd.read_csv("data.csv")
new_facilities = df[df["công_bố_mới"] == 1.0].copy()

# Better date parsing - use dayfirst=True explicitly
def parse_date(val):
    if pd.isna(val):
        return pd.NaT
    s = str(val).strip().rstrip('.')
    if '(' in s:
        s = s.split('(')[0].strip()
    try:
        return pd.to_datetime(s, dayfirst=True, errors='coerce')
    except:
        return pd.NaT

new_facilities['date_parsed'] = new_facilities['ngày_công_bố'].apply(parse_date)

# Let's see all unique dates sorted
dates_sorted = sorted(new_facilities['date_parsed'].unique())
print("All unique dates:")
for d in dates_sorted:
    print(d)

print("\nMax date:", max(dates_sorted))
latest = new_facilities[new_facilities['date_parsed'] == max(dates_sorted)]
print("\nLatest entries:")
print(latest[['stt', 'ngày_công_bố', 'tên_cơ_sở']].to_string())
"}
